// ── Independent font slot cascade through basedOn ─────────────

/// ISO 29500-1 §17.3.2.26: Each font slot cascades independently.
/// Child overrides ascii only; eastAsia and cs inherit from parent.
///
/// Independent font slot cascade through basedOn.
#[test]
fn fsa_ascii_only_child_inherits_other_slots() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "ascii-only-independent-slots");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Child overrides"))
        .expect("should find child override paragraph");

    let nodes = text_nodes(p);
    let run = &nodes[0];

    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Trebuchet MS"),
        "ascii font should be 'Trebuchet MS' from child style. \
         Got {:?}.",
        run.style_props.font_family
    );
    assert_eq!(
        run.style_props.font_east_asia.as_deref(),
        Some("SimSun"),
        "eastAsia should inherit 'SimSun' from parent (child has no eastAsia). \
         Got {:?}.",
        run.style_props.font_east_asia
    );
    assert_eq!(
        run.style_props.font_cs.as_deref(),
        Some("Arial Unicode MS"),
        "cs should inherit 'Arial Unicode MS' from parent (child has no cs). \
         Got {:?}.",
        run.style_props.font_cs
    );
}

// ── szCs from style chain with direct cs ──────────────────────

/// MS-OI29500 §17.3.2.39: When cs=true, font size comes from szCs.
/// szCs should resolve from the character style chain even when cs
/// is set only in direct formatting.
///
/// szCs from style chain with direct cs activation.
#[test]
fn fsa_szcs_from_style_when_cs_direct() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "szcs-from-style-chain");
    let paras = common::all_paragraphs(&doc);

    let nodes = text_nodes(paras[0]);

    let cs_run = nodes
        .iter()
        .find(|n| n.text.contains("SzCs from style"))
        .expect("should find SzCs from style run");

    // cs=true: should use szCs=32 from char style instead of sz=24
    assert_eq!(
        cs_run.style_props.font_size,
        Some(32),
        "cs=true run should use szCs=32 (16pt) from char style, not sz=24 (12pt). \
         Got font_size={:?}. MS-OI29500 §17.3.2.39.",
        cs_run.style_props.font_size
    );

    // cs=true: font_family should be cs font
    assert_eq!(
        cs_run.style_props.font_family.as_deref(),
        Some("David"),
        "cs=true run should use cs font 'David'. \
         Got font_family={:?}.",
        cs_run.style_props.font_family
    );
}

/// Positive test: without cs, sz is used instead of szCs.
#[test]
fn fsa_sz_from_style_when_no_cs() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "szcs-from-style-chain");
    let paras = common::all_paragraphs(&doc);

    let nodes = text_nodes(paras[0]);

    let no_cs_run = nodes
        .iter()
        .find(|n| n.text.contains("Sz from style"))
        .expect("should find Sz from style run");

    // No cs: should use sz=24
    assert_eq!(
        no_cs_run.style_props.font_size,
        Some(24),
        "Non-cs run should use sz=24 (12pt) from char style. \
         Got font_size={:?}.",
        no_cs_run.style_props.font_size
    );

    // No cs: font_family should be ascii font
    assert_eq!(
        no_cs_run.style_props.font_family.as_deref(),
        Some("Arial"),
        "Non-cs run should use ascii font 'Arial'. \
         Got font_family={:?}.",
        no_cs_run.style_props.font_family
    );
}
